/**
 * Health Dashboard Engine
 *
 * Pure functions for computing, formatting and evaluating
 * application health metrics.
 */

// ─── Types ───────────────────────────────────────────────────────────

export interface HealthDashboardData {
  timestamp: string;
  uptime: UptimeInfo;
  services: ServiceStatus[];
  api: ApiMetrics;
  queue: QueueMetrics;
  storage: StorageMetrics;
  system: SystemMetrics;
  overall: OverallHealth;
}

export interface UptimeInfo {
  startedAt: string;
  uptimeSeconds: number;
  formatted: string; // "3d 14h 22m"
}

export type ServiceState = 'healthy' | 'degraded' | 'down' | 'unknown';

export interface ServiceStatus {
  name: string; // 'PostgreSQL', 'Redis', 'Supabase Auth', 'S3/Storage', 'Stripe'
  state: ServiceState;
  latencyMs: number | null;
  lastChecked: string;
  message: string | null;
}

export interface ApiMetrics {
  totalRequests: number;
  successRate: number; // 0-100
  errorRate: number; // 0-100
  avgLatencyMs: number;
  p95LatencyMs: number;
  p99LatencyMs: number;
  topEndpoints: EndpointMetric[];
  errorsByStatus: Record<number, number>; // { 400: 5, 500: 2, ... }
}

export interface EndpointMetric {
  path: string;
  method: string;
  count: number;
  avgLatencyMs: number;
  errorCount: number;
}

export interface QueueMetrics {
  activeJobs: number;
  waitingJobs: number;
  completedJobs: number;
  failedJobs: number;
  delayedJobs: number;
  avgProcessingTimeMs: number;
  throughputPerMinute: number;
}

export interface StorageMetrics {
  totalUsedBytes: number;
  totalFiles: number;
  breakdown: Record<string, number>; // { 'videos': bytes, 'images': bytes, ... }
  quotaBytes: number | null;
  usagePercent: number;
}

export interface SystemMetrics {
  nodeVersion: string;
  memoryUsedMB: number;
  memoryTotalMB: number;
  memoryPercent: number;
  cpuUsagePercent: number;
  activeConnections: number;
}

export type HealthLevel = 'healthy' | 'warning' | 'critical';

export interface OverallHealth {
  level: HealthLevel;
  score: number; // 0-100
  issues: HealthIssue[];
}

export interface HealthIssue {
  severity: 'warning' | 'critical';
  component: string;
  message: string;
}

export interface MetricTrend {
  current: number;
  previous: number;
  changePercent: number;
  direction: 'up' | 'down' | 'stable';
}

// ─── Constants ───────────────────────────────────────────────────────

export const HEALTH_THRESHOLDS = {
  apiSuccessRate: { warning: 95, critical: 90 },
  apiLatencyMs: { warning: 500, critical: 2000 },
  queueFailedPercent: { warning: 5, critical: 15 },
  memoryPercent: { warning: 80, critical: 95 },
  storagePercent: { warning: 80, critical: 95 },
  serviceLatencyMs: { warning: 200, critical: 1000 },
} as const;

export const REFRESH_INTERVAL_MS = 30_000; // 30 seconds
export const METRIC_HISTORY_LENGTH = 60; // keep last 60 data points

// ─── Formatting Helpers ──────────────────────────────────────────────

/**
 * Format uptime seconds to human-readable string.
 * e.g. 300_000 → "3d 11h 20m", 135 → "2m 15s"
 */
export function formatUptime(seconds: number): string {
  if (seconds < 0) return '0s';

  const days = Math.floor(seconds / 86_400);
  const hours = Math.floor((seconds % 86_400) / 3_600);
  const minutes = Math.floor((seconds % 3_600) / 60);
  const secs = Math.floor(seconds % 60);

  const parts: string[] = [];
  if (days > 0) parts.push(`${days}d`);
  if (hours > 0) parts.push(`${hours}h`);
  if (minutes > 0) parts.push(`${minutes}m`);
  if (parts.length === 0) parts.push(`${secs}s`);

  return parts.join(' ');
}

/**
 * Format bytes to human-readable string.
 * e.g. 1_500_000_000 → "1.4 GB"
 */
export function formatBytes(bytes: number): string {
  if (bytes === 0) return '0 B';
  if (bytes < 0) return '0 B';

  const units = ['B', 'KB', 'MB', 'GB', 'TB'];
  const k = 1024;
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  const idx = Math.min(i, units.length - 1);
  const value = bytes / Math.pow(k, idx);

  return `${value % 1 === 0 ? value.toString() : value.toFixed(1)} ${units[idx]}`;
}

/**
 * Format latency in milliseconds.
 * e.g. 23 → "23ms", 1200 → "1.2s"
 */
export function formatLatency(ms: number): string {
  if (ms < 1000) {
    return `${Math.round(ms)}ms`;
  }
  return `${(ms / 1000).toFixed(1)}s`;
}

/**
 * Format number with locale-aware separators.
 * e.g. 1234 → "1,234", 12500 → "12.5K", 1200000 → "1.2M"
 */
export function formatNumber(n: number): string {
  if (n >= 1_000_000) {
    const val = n / 1_000_000;
    return `${val % 1 === 0 ? val.toString() : val.toFixed(1)}M`;
  }
  if (n >= 10_000) {
    const val = n / 1_000;
    return `${val % 1 === 0 ? val.toString() : val.toFixed(1)}K`;
  }
  return n.toLocaleString('en-US');
}

/**
 * Format percentage value.
 * e.g. 98.5 → "98.5%", 100 → "100%"
 */
export function formatPercent(value: number, decimals = 1): string {
  if (value === 0) return '0%';
  if (value === 100) return '100%';
  const formatted = value.toFixed(decimals);
  // Remove trailing zeros after decimal point
  const cleaned = formatted.replace(/\.0+$/, '');
  return `${cleaned}%`;
}

// ─── Health Evaluation ───────────────────────────────────────────────

/**
 * Evaluate a metric against warning/critical thresholds.
 * @param inverted If true, lower values are worse (e.g. success rate); if false, higher values are worse (e.g. latency)
 */
export function evaluateMetricLevel(
  value: number,
  thresholds: { warning: number; critical: number },
  inverted = false,
): HealthLevel {
  if (inverted) {
    // For "higher is better" metrics like success rate
    if (value <= thresholds.critical) return 'critical';
    if (value <= thresholds.warning) return 'warning';
    return 'healthy';
  }
  // For "lower is better" metrics like latency, memory%
  if (value >= thresholds.critical) return 'critical';
  if (value >= thresholds.warning) return 'warning';
  return 'healthy';
}

/**
 * Evaluate service health based on latency and current state.
 */
export function evaluateServiceHealth(service: ServiceStatus): ServiceState {
  if (service.state === 'down') return 'down';
  if (service.latencyMs === null) return service.state;

  if (service.latencyMs >= HEALTH_THRESHOLDS.serviceLatencyMs.critical) return 'down';
  if (service.latencyMs >= HEALTH_THRESHOLDS.serviceLatencyMs.warning) return 'degraded';
  return 'healthy';
}

/**
 * Calculate overall health score from component metrics.
 *
 * Weights:
 * - API success rate: 30%
 * - Services health: 30%
 * - Queue health: 20%
 * - System resources: 20%
 */
export function calculateHealthScore(data: {
  apiSuccessRate: number;
  servicesHealthy: number;
  totalServices: number;
  queueFailedPercent: number;
  memoryPercent: number;
}): number {
  const apiScore = data.apiSuccessRate; // 0-100
  const serviceScore = data.totalServices > 0
    ? (data.servicesHealthy / data.totalServices) * 100
    : 100;
  const queueScore = Math.max(0, 100 - data.queueFailedPercent * 5);
  const memoryScore = Math.max(0, 100 - Math.max(0, data.memoryPercent - 50) * 2);

  const score = apiScore * 0.3 + serviceScore * 0.3 + queueScore * 0.2 + memoryScore * 0.2;
  return Math.round(Math.min(100, Math.max(0, score)));
}

/**
 * Compute overall health from all metrics.
 */
export function computeOverallHealth(
  data: Omit<HealthDashboardData, 'overall'>,
): OverallHealth {
  const issues: HealthIssue[] = [];

  // API checks
  const apiLevel = evaluateMetricLevel(
    data.api.successRate,
    HEALTH_THRESHOLDS.apiSuccessRate,
    true,
  );
  if (apiLevel !== 'healthy') {
    issues.push({
      severity: apiLevel === 'critical' ? 'critical' : 'warning',
      component: 'API',
      message: `Success rate is ${formatPercent(data.api.successRate)} (threshold: ${HEALTH_THRESHOLDS.apiSuccessRate[apiLevel]}%)`,
    });
  }

  const latencyLevel = evaluateMetricLevel(
    data.api.avgLatencyMs,
    HEALTH_THRESHOLDS.apiLatencyMs,
  );
  if (latencyLevel !== 'healthy') {
    issues.push({
      severity: latencyLevel === 'critical' ? 'critical' : 'warning',
      component: 'API',
      message: `Average latency is ${formatLatency(data.api.avgLatencyMs)} (threshold: ${HEALTH_THRESHOLDS.apiLatencyMs[latencyLevel]}ms)`,
    });
  }

  // Service checks
  for (const service of data.services) {
    const evaluated = evaluateServiceHealth(service);
    if (evaluated === 'down') {
      issues.push({
        severity: 'critical',
        component: service.name,
        message: `Service is down${service.message ? `: ${service.message}` : ''}`,
      });
    } else if (evaluated === 'degraded') {
      issues.push({
        severity: 'warning',
        component: service.name,
        message: `Service is degraded (latency: ${formatLatency(service.latencyMs ?? 0)})`,
      });
    }
  }

  // Queue checks
  const totalJobs = data.queue.completedJobs + data.queue.failedJobs;
  const queueFailedPercent = totalJobs > 0
    ? (data.queue.failedJobs / totalJobs) * 100
    : 0;
  const queueLevel = evaluateMetricLevel(
    queueFailedPercent,
    HEALTH_THRESHOLDS.queueFailedPercent,
  );
  if (queueLevel !== 'healthy') {
    issues.push({
      severity: queueLevel === 'critical' ? 'critical' : 'warning',
      component: 'Queue',
      message: `Failed jobs rate is ${formatPercent(queueFailedPercent)} (threshold: ${HEALTH_THRESHOLDS.queueFailedPercent[queueLevel]}%)`,
    });
  }

  // Memory checks
  const memoryLevel = evaluateMetricLevel(
    data.system.memoryPercent,
    HEALTH_THRESHOLDS.memoryPercent,
  );
  if (memoryLevel !== 'healthy') {
    issues.push({
      severity: memoryLevel === 'critical' ? 'critical' : 'warning',
      component: 'System',
      message: `Memory usage is ${formatPercent(data.system.memoryPercent)} (threshold: ${HEALTH_THRESHOLDS.memoryPercent[memoryLevel]}%)`,
    });
  }

  // Storage checks
  const storageLevel = evaluateMetricLevel(
    data.storage.usagePercent,
    HEALTH_THRESHOLDS.storagePercent,
  );
  if (storageLevel !== 'healthy') {
    issues.push({
      severity: storageLevel === 'critical' ? 'critical' : 'warning',
      component: 'Storage',
      message: `Storage usage is ${formatPercent(data.storage.usagePercent)} (threshold: ${HEALTH_THRESHOLDS.storagePercent[storageLevel]}%)`,
    });
  }

  // Compute score
  const healthyServices = data.services.filter(
    (s) => evaluateServiceHealth(s) === 'healthy',
  ).length;

  const score = calculateHealthScore({
    apiSuccessRate: data.api.successRate,
    servicesHealthy: healthyServices,
    totalServices: data.services.length,
    queueFailedPercent,
    memoryPercent: data.system.memoryPercent,
  });

  // Determine overall level
  let level: HealthLevel = 'healthy';
  if (issues.some((i) => i.severity === 'critical')) {
    level = 'critical';
  } else if (issues.some((i) => i.severity === 'warning')) {
    level = 'warning';
  }

  return { level, score, issues };
}

// ─── Trend Computation ───────────────────────────────────────────────

/**
 * Compute metric trend (direction + change percentage).
 */
export function computeTrend(current: number, previous: number): MetricTrend {
  if (previous === 0) {
    return {
      current,
      previous,
      changePercent: current > 0 ? 100 : 0,
      direction: current > 0 ? 'up' : 'stable',
    };
  }

  const changePercent = ((current - previous) / Math.abs(previous)) * 100;
  const rounded = Math.round(changePercent * 10) / 10;

  let direction: MetricTrend['direction'] = 'stable';
  if (rounded > 1) direction = 'up';
  else if (rounded < -1) direction = 'down';

  return {
    current,
    previous,
    changePercent: rounded,
    direction,
  };
}

// ─── Visual Helpers ──────────────────────────────────────────────────

/**
 * Returns tailwind text color class for health level.
 */
export function getHealthColor(level: HealthLevel): string {
  switch (level) {
    case 'healthy':
      return 'text-green-500';
    case 'warning':
      return 'text-yellow-500';
    case 'critical':
      return 'text-red-500';
  }
}

/**
 * Returns tailwind background color class for health level.
 */
export function getHealthBgColor(level: HealthLevel): string {
  switch (level) {
    case 'healthy':
      return 'bg-green-500/10';
    case 'warning':
      return 'bg-yellow-500/10';
    case 'critical':
      return 'bg-red-500/10';
  }
}

/**
 * Returns icon name for service state.
 */
export function getServiceStateIcon(state: ServiceState): string {
  switch (state) {
    case 'healthy':
      return 'CheckCircle';
    case 'degraded':
      return 'AlertTriangle';
    case 'down':
      return 'XCircle';
    case 'unknown':
      return 'HelpCircle';
  }
}

/**
 * Group HTTP error codes into client (4xx) and server (5xx) categories.
 */
export function groupErrorsByStatus(
  errors: Record<number, number>,
): { client: number; server: number; total: number } {
  let client = 0;
  let server = 0;

  for (const [statusStr, count] of Object.entries(errors)) {
    const status = Number(statusStr);
    if (status >= 400 && status < 500) {
      client += count;
    } else if (status >= 500 && status < 600) {
      server += count;
    }
  }

  return { client, server, total: client + server };
}

